import { useState } from "react";

import { backendURL } from "../Globals";
import { Table } from "antd";


let SearchComponent = (props) => {

let [issn,setIssn] = useState("")

let [message, setMessage] = useState("")

    let onChangeIssn = (e) => {
        setIssn(e.currentTarget.value)
    }

    let clickSearch = async () => {
        let response = await fetch(backendURL+"/journals/"+issn, {
            method: "GET",
            mode: "cors",
            headers: { "Content-Type": "application/json" },
            params: JSON.stringify({
                issn: issn
            })
        })

        if ( response.ok ){
            let jsonData = await response.json();
            setMessage(JSON.stringify(jsonData))
        } else {
            let jsonData = await response.json();
            setMessage(jsonData.error+": "+issn)
        }
    }

    let columns = [
        {
            title: "Título",
            dataIndex: "title"
        },  
        {
            title: "ISSN",
            dataIndex: "issn"
        },  
        {
            title: "Editorial",
            dataIndex: "publisher"
        },  
        {
            title: "Cobertura APCs",
            dataIndex: ""
        },  
    ]

    return (
       
        <div className="search-form">
            <hr></hr>
            <h1>Acuerdos Transformativos UniOvi</h1>
            <hr></hr>
            <h2>Encuentra una revista participante</h2>
            <input type="text" className="search-input" placeholder="Encuentra una revista por ISSN" onChange={onChangeIssn}/>
            <button onClick={() => {clickSearch()}} className="search-button">Buscar</button>
            <div>{message}</div>
            <Table columns={columns}/>
            <p>Con los Acuerdos Transformativos las bibliotecas universiarias han conseguido que una parte de la inversión en suscripciones a los big deals de las editoriales sea ahora empleado en sufragar publicaciones en abierto.</p>   
            <p>Los autores y autoras que se beneficien de estos acuerdos para publicar en acceso abierto conservarán sus derechos morales de propiedad intelectual gracias a las licencias creative commons.</p>
        </div>
        

    )
}

export default SearchComponent;
